    <tr><td style="padding:10px 12px;border:1px solid rgba(255,255,255,0.1)"><strong>Content length preference</strong></td><td style="padding:10px 12px;border:1px solid rgba(255,255,255,0.1)">Longer tends to rank</td><td style="padding:10px 12px;border:1px solid rgba(255,255,255,0.1)">Length matters less; structure dominates</td></tr>
